		public void AI()
		{
			if (aiStyle == 0)
			{
				for (int i = 0; i < 255; i++)
				{
					if (Main.player[i].active && Main.player[i].talkNPC == whoAmI)
					{
						if (type == 105)
						{
							Transform(107);
							return;
						}
						if (type == 106)
						{
							Transform(108);
							return;
						}
						if (type == 123)
						{
							Transform(124);
							return;
						}
						if (type == 354)
						{
							Transform(353);
							return;
						}
						if (type == 376)
						{
							Transform(369);
							return;
						}
					}
				}
				if (type != 376)
				{
					TargetClosest();
					spriteDirection = direction;
				}
				if (type == 376)
				{
					if (wet || Main.tile[(int)(center().X / 16f), (int)(position.Y - 4f) / 16].liquid > 0)
					{
						velocity.Y = -0.4f;
						int num = 1;
						if (center().X / 16f > (float)(Main.maxTilesX / 2))
						{
							num = -1;
						}
						int num2 = 12;
						int num3 = (int)center().X / 16;
						int j = (int)center().Y / 16;
						bool flag = false;
						if (num > 0)
						{
							for (int k = num3; k < num3 + num2; k++)
							{
								if (WorldGen.SolidTile(k, j))
								{
									flag = true;
								}
							}
						}
						else
						{
							for (int num4 = num3; num4 > num3 - num2; num4--)
							{
								if (WorldGen.SolidTile(num4, j))
								{
									flag = true;
								}
							}
						}
						if (flag)
						{
							velocity.X *= 0.99f;
							if ((double)velocity.X > -0.01 && (double)velocity.X < 0.01)
							{
								velocity.X = 0f;
							}
						}
						else
						{
							velocity.X += (float)num * 0.01f;
							if (velocity.X > 0.2f)
							{
								velocity.X *= 0.95f;
							}
							if (velocity.X < -0.2f)
							{
								velocity.X *= 0.95f;
							}
						}
					}
					velocity.X *= 0.93f;
					if ((double)velocity.X > -0.1 && (double)velocity.X < 0.1)
					{
						velocity.X = 0f;
					}
				}
				else
				{
					velocity.X *= 0.93f;
					if ((double)velocity.X > -0.1 && (double)velocity.X < 0.1)
					{
						velocity.X = 0f;
					}
				}
				return;
			}
			if (aiStyle == 1)
			{
				if (type == 244)
				{
					float num5 = (float)Main.DiscoR / 255f;
					float num6 = (float)Main.DiscoG / 255f;
					float num7 = (float)Main.DiscoB / 255f;
					num5 *= 1f;
					num6 *= 1f;
					num7 *= 1f;
					Lighting.addLight((int)((position.X + (float)(width / 2)) / 16f), (int)((position.Y + (float)(height / 2)) / 16f), num5, num6, num7);
					color.R = (byte)Main.DiscoR;
					color.G = (byte)Main.DiscoG;
					color.B = (byte)Main.DiscoB;
					color.A = 100;
					alpha = 175;
				}
				bool flag2 = false;
				if (!Main.dayTime || life != lifeMax || (double)position.Y > Main.worldSurface * 16.0)
				{
					flag2 = true;
				}
				if (type == 81)
				{
					flag2 = true;
					if (Main.rand.Next(30) == 0)
