		public void TargetClosest(bool faceTarget = true)
		{
			float num = 0f;
			float num2 = 0f;
			bool flag = false;
			for (int i = 0; i < 255; i++)
			{
				if (Main.player[i].active && !Main.player[i].dead)
				{
					float num3 = Math.Abs(Main.player[i].position.X + (float)(Main.player[i].width / 2) - position.X + (float)(width / 2)) + Math.Abs(Main.player[i].position.Y + (float)(Main.player[i].height / 2) - position.Y + (float)(height / 2));
					num3 -= (float)Main.player[i].aggro;
					if (!flag || num3 < num)
					{
						flag = true;
						num2 = Math.Abs(Main.player[i].position.X + (float)(Main.player[i].width / 2) - position.X + (float)(width / 2)) + Math.Abs(Main.player[i].position.Y + (float)(Main.player[i].height / 2) - position.Y + (float)(height / 2));
						num = num3;
						target = i;
					}
				}
			}
			if (target < 0 || target >= 255)
			{
				target = 0;
			}
			targetRect = new Rectangle((int)Main.player[target].position.X, (int)Main.player[target].position.Y, Main.player[target].width, Main.player[target].height);
			if (Main.player[target].dead)
			{
				faceTarget = false;
			}
			if (faceTarget)
			{
				float num4 = num2 - (float)Main.player[target].aggro;
				float num5 = (Main.player[target].height + Main.player[target].width + height + width) / 4 + 750 + 50;
				if (Main.player[target].itemAnimation != 0 || Main.player[target].aggro >= 0 || !(num4 > num5) || oldTarget < 0 || oldTarget > 254)
				{
					direction = 1;
					if ((float)(targetRect.X + targetRect.Width / 2) < position.X + (float)(width / 2))
					{
						direction = -1;
					}
					directionY = 1;
					if ((float)(targetRect.Y + targetRect.Height / 2) < position.Y + (float)(height / 2))
					{
						directionY = -1;
					}
				}
			}
			if (confused)
			{
				direction *= -1;
			}
