		public double StrikeNPC(int Damage, float knockBack, int hitDirection, bool crit = false, bool noEffect = false)
		{
			if (!active || life <= 0)
			{
				return 0.0;
			}
			double num = Damage;
			num = ((!ichor) ? Main.CalculateDamage((int)num, defense) : Main.CalculateDamage((int)num, defense - 20));
			if (crit)
			{
				num *= 2.0;
			}
			if (Damage != 9999 && lifeMax > 1)
			{
				if (friendly)
				{
					CombatText.NewText(new Rectangle((int)position.X, (int)position.Y, width, height), new Color(255, 80, 90, 255), string.Concat((int)num), crit);
				}
				else
				{
					CombatText.NewText(new Rectangle((int)position.X, (int)position.Y, width, height), new Color(255, 160, 80, 255), string.Concat((int)num), crit);
				}
			}
			if (num >= 1.0)
			{
				justHit = true;
				if (townNPC)
				{
					ai[0] = 1f;
					ai[1] = 300 + Main.rand.Next(300);
					ai[2] = 0f;
					direction = hitDirection;
					netUpdate = true;
				}
				if (aiStyle == 8 && Main.netMode != 1)
				{
					if (type == 172)
					{
						ai[0] = 450f;
					}
					else
					{
						ai[0] = 400f;
					}
					TargetClosest();
				}
				if (type == 371)
				{
					num = 0.0;
					ai[0] = 1f;
					ai[1] = 4f;
					dontTakeDamage = true;
				}
				if (type == 346 && (double)life >= (double)lifeMax * 0.5 && (double)life - num < (double)lifeMax * 0.5)
				{
					Gore.NewGore(position, velocity, 517);
				}
				if (type == 184)
				{
					localAI[0] = 60f;
				}
				if (type == 185)
				{
					localAI[0] = 1f;
				}
				if (realLife >= 0)
				{
					Main.npc[realLife].life -= (int)num;
					life = Main.npc[realLife].life;
					lifeMax = Main.npc[realLife].lifeMax;
				}
				else
				{
					life -= (int)num;
				}
				if (knockBack > 0f && knockBackResist > 0f)
				{
					float num2 = knockBack * knockBackResist;
					if (num2 > 8f)
					{
						num2 = 8f;
					}
					if (crit)
					{
						num2 *= 1.4f;
					}
					if (num * 10.0 > (double)lifeMax)
					{
						if (hitDirection < 0 && velocity.X > 0f - num2)
						{
							if (velocity.X > 0f)
							{
								velocity.X -= num2;
							}
							velocity.X -= num2;
							if (velocity.X < 0f - num2)
							{
								velocity.X = 0f - num2;
							}
						}
						else if (hitDirection > 0 && velocity.X < num2)
						{
							if (velocity.X < 0f)
							{
								velocity.X += num2;
							}
							velocity.X += num2;
							if (velocity.X > num2)
							{
								velocity.X = num2;
							}
						}
						if (type == 185)
						{
							num2 *= 1.5f;
						}
						num2 = (noGravity ? (num2 * -0.5f) : (num2 * -0.75f));
						if (velocity.Y > num2)
						{
							velocity.Y += num2;
							if (velocity.Y < num2)
							{
								velocity.Y = num2;
							}
						}
					}
					else
					{
						if (!noGravity)
						{
							velocity.Y = (0f - num2) * 0.75f * knockBackResist;
						}
						else
						{
							velocity.Y = (0f - num2) * 0.5f * knockBackResist;
						}
						velocity.X = num2 * (float)hitDirection * knockBackResist;
					}
				}
				if ((type == 113 || type == 114) && life <= 0)
				{
					for (int i = 0; i < 200; i++)
					{
						if (Main.npc[i].active && (Main.npc[i].type == 113 || Main.npc[i].type == 114))
						{
							Main.npc[i].HitEffect(hitDirection, num);
						}
					}
				}
				else
				{
					HitEffect(hitDirection, num);
				}
				if (soundHit > 0)
				{
					Main.PlaySound(3, (int)position.X, (int)position.Y, soundHit);
				}
				if (realLife >= 0)
				{
					Main.npc[realLife].checkDead();
				}
				else
				{
					checkDead();
				}
				return num;
			}
			return 0.0;
		}

		public void checkDead()
		{
			if (!active || (realLife >= 0 && realLife != whoAmI) || life > 0)
			{
				return;
			}
			noSpawnCycle = true;
			if (townNPC && type != 37)
			{
				string text = name;
				if (displayName != "")
				{
					text = displayName;
				}
				if (Main.netMode == 0)
				{
					if (type == 369)
					{
						Main.NewText(text + Lang.misc[36], byte.MaxValue, 25, 25);
					}
					else
					{
						Main.NewText(text + Lang.misc[19], byte.MaxValue, 25, 25);
					}
				}
				else if (Main.netMode == 2)
				{
					if (type == 369)
					{
						NetMessage.SendData(25, -1, -1, text + Lang.misc[36], 255, 255f, 25f, 25f);
