		public void HitEffect(int hitDirection = 0, double dmg = 10.0)
		{
			if (!active)
			{
				return;
			}
			if (type == 372 || type == 373)
			{
				if (life > 0)
				{
					for (int i = 0; (double)i < dmg / (double)lifeMax * 100.0; i++)
					{
						Dust.NewDust(position, width, height, 5, hitDirection, -1f);
					}
				}
				else
				{
					for (int j = 0; j < 75; j++)
					{
						int num = Dust.NewDust(center() - Vector2.One * 25f, 50, 50, 5, 2 * hitDirection, -2f);
						Main.dust[num].velocity /= 2f;
					}
					Gore.NewGore(center(), velocity * 0.8f, 583);
					Gore.NewGore(center(), velocity * 0.8f, 577);
					Gore.NewGore(center(), velocity * 0.9f, 578);
					Gore.NewGore(center(), velocity, 579);
				}
			}
			if (type == 371)
			{
				Main.PlaySound(4, (int)position.X, (int)position.Y, 3);
				if (life <= 0)
				{
					center();
					for (int k = 0; k < 60; k++)
