				int num2 = (int)(position.Y + (float)(height / 2)) / 16;
				try
				{
					if (num >= 4 && num <= Main.maxTilesX - 4 && num2 >= 4 && num2 <= Main.maxTilesY - 4)
					{
						if (Main.tile[num, num2] == null)
						{
							flag = true;
						}
						else if (Main.tile[num - 3, num2] == null)
						{
							flag = true;
						}
						else if (Main.tile[num + 3, num2] == null)
						{
							flag = true;
						}
						else if (Main.tile[num, num2 - 3] == null)
						{
							flag = true;
						}
						else if (Main.tile[num, num2 + 3] == null)
						{
							flag = true;
						}
					}
				}
				catch
				{
					flag = true;
				}
				if (flag)
				{
					return;
				}
			}
			lifeRegen = 0;
			poisoned = false;
			venom = false;
			onFire = false;
			midas = false;
			ichor = false;
			onFrostBurn = false;
			onFire2 = false;
			confused = false;
			loveStruck = false;
			stinky = false;
			dripping = false;
			drippingSlime = false;
			for (int k = 0; k < 5; k++)
			{
				if (buffType[k] > 0 && buffTime[k] > 0)
				{
					buffTime[k]--;
					if (buffType[k] == 20)
					{
						poisoned = true;
					}
					if (buffType[k] == 70)
					{
						venom = true;
					}
					if (buffType[k] == 24)
